args.sparql:
SELECT ?band ?bandLabel WHERE {
  wd:Q15224805 wdt:P710 ?band .
  ?band wdt:P31/wdt:P279* wd:Q2088355 ;
        wdt:P264 wd:Q21178769 ;
        rdfs:label ?bandLabel .
  ?band wdt:P136 ?genre .
  ?genre rdfs:label ?genreLabel .
  FILTER(LANG(?bandLabel) = "en")
  FILTER(LANG(?genreLabel) = "en")
  FILTER(CONTAINS(LCASE(?genreLabel), "indie"))
  FILTER(CONTAINS(LCASE(?bandLabel), "checks"))
}
